sys_script_include.script:
var IncidentEscalationEngine = Class.create();
IncidentEscalationEngine.prototype = {

    initialize: function(incidentSysId) {
        this.incidentSysId = incidentSysId;
        this._gr = new GlideRecord('incident');
        this._gr.get(incidentSysId);
    },

    escalate: function(escalationType) {
        if (!this._gr.isValidRecord()) {
            gs.error('IncidentEscalationEngine: Invalid incident sys_id ' + this.incidentSysId);
            return false;
        }

        switch (escalationType) {
            case 'SLA_WARNING':
                return this._handleWarning();
            case 'SLA_BREACH':
                return this._handleBreach();
            default:
                gs.warn('IncidentEscalationEngine: Unknown escalation type ' + escalationType);
                return false;
        }
    },

    _handleWarning: function() {
        this._notifyManager('SLA breach imminent for ' + this._gr.number + '. Please review.');
        this._auditEscalation('SLA_WARNING');
        return true;
    },

    _notifyManager: function(message) {
        var assignmentGroup = this._gr.assignment_group.toString();
        if (!assignmentGroup) return;

        var grpGr = new GlideRecord('sys_user_group');
        if (!grpGr.get(assignmentGroup)) return;

        var managerSysId = grpGr.manager.toString();
        if (!managerSysId) return;

        gs.eventQueue(
            'x_itsm_ilc.incident.escalation_notify',
            this._gr,
            managerSysId,
            message
        );
    },

    _auditEscalation: function(escalationType) {
        var auditGr = new GlideRecord('u_incident_escalation_audit');
        auditGr.initialize();
        auditGr.u_incident             = this.incidentSysId;
        auditGr.u_escalation_type      = escalationType;
        auditGr.u_triggered_on         = new GlideDateTime();
        auditGr.u_priority_at_trigger  = this._gr.priority.toString();
        auditGr.insert();
    },

    type: 'IncidentEscalationEngine'
};
